import db from '../../utils/session/db.js'
import logger from '../../utils/logger.js'
import * as cheerio from 'cheerio'
import axios from 'axios'
import sharp from 'sharp'

const STORAGE_KEY = 'DyePredictor';

export const command = {
	command: 'dye',
	tag: 'Toram Online',
	description: 'Prediksi drop dye senjata.',
	get help() {
		return `usage: .dye [color]`
	},
	handle: async (bot, m) => {
		await m.reply({ react: { text: '🔎', key: m.key } }, false)
		try {
			const colors = await dyePredictor(m.arguments[0]?.toUpperCase()||'')
			if(colors.err)
				await m.reply(colors.err)
			else if(colors.length < 1)
				await m.reply('tidak ditemukan..')
			else {
				const date = new Date
				const body = `Color Weapon ( ${date.getFullYear()}${String(date.getMonth() +1).padStart(2,0)} )\n\nsumber: tanaka0.work`
				await m.reply({
					image: await createColorList(colors),
					caption: body
				}, true, { ephemeralExpiration: 86400 })
			}
		} catch(e) {
			logger.error(e, 'Color-List')
			await m.reply('maaf, terjadi kesalahan..')
		}
		await m.reply({ react: { text: '', key: m.key } }, false)
	},
}

async function dyePredictor(f) {
	if (!dyePredictor.data)
	
	FETCH_DATA:
	try {
		const date = (new Date).toJSON().slice(0,7)
		let store = await db.get(STORAGE_KEY)
		
		if (store && store.date == date) {
			dyePredictor.data = store.data
			break FETCH_DATA
		}
		
		store = {date}
		
		const response = await axios.get('https://tanaka0.work/AIO/en/DyePredictor/ColorWeapon')
		if (global.devMode) logger.info(`Status Code: ${response.status}`);
		
		const $ = cheerio.load(response.data)
		let result = []
		let ctble = $('.color-wep-table')
			ctble.each((i,o) => {
				o = $(o)
				o.find('tbody tr').each((i,o) => {
					o = $(o)
					const data = {}
					data.name = o.find('td:first').text().trim().replace(/\s+/g, ' ')
					data.color = o.find('td:last font').attr('style')?.match(/color:\s*([^;]+)/)?.[1].trim() || '#ffffff'
					data.colorName = o.find('td:last').text().match(/[ABC0-9]{2,3}|Hidden/i)?.[0] || 'Unknown'
					result.push(data)
				})
			})
			dyePredictor.data = store.data = result
			await db.save(STORAGE_KEY, store)
	} catch({code,status}) {
		if (global.devMode) logger.warn(`Status: ${status}/${code}`);
		return {err:`Status: ${status}/${code}`}
	}
	
	const { data } = dyePredictor
	if(f)
		return data.filter(a=>a.colorName == f)
	return data
}

// Here, script generated by DeepSeekAI

/**
 * Escape karakter berbahaya untuk XML/SVG
 */
function escapeXml(str) {
  return str.replace(/[&<>]/g, function (m) {
    if (m === '&') return '&amp;';
    if (m === '<') return '&lt;';
    if (m === '>') return '&gt;';
    return m;
  });
}

/**
 * Menentukan warna teks (hitam atau putih) berdasarkan kecerahan latar belakang
 */
function getContrastColor(hex) {
  let raw = hex.charAt(0) === '#' ? hex.slice(1) : hex;
  if (raw.length === 3) {
    raw = raw.split('').map(c => c + c).join('');
  }
  const r = parseInt(raw.slice(0, 2), 16);
  const g = parseInt(raw.slice(2, 4), 16);
  const b = parseInt(raw.slice(4, 6), 16);
  const luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255;
  return luminance > 0.5 ? '#000000' : '#ffffff';
}

/**
 * Membuat gambar tabel daftar warna
 * @param {Array<{name: string, color: string, colorName: string}>} arr 
 * @returns {Promise<string>} path ke file gambar PNG
 */
async function createColorList(arr) {
  // Konfigurasi layout (dalam piksel)
  const VERTICAL_MARGIN = 20;
  const HORIZONTAL_MARGIN = 20;
  const TABLE_MARGIN = 16;       // margin antar tabel
  const COL1_WIDTH = 300;        // lebar kolom pertama (nama)
  const COL2_WIDTH = 50;         // lebar kolom kedua (warna)
  const TABLE_WIDTH = COL1_WIDTH + COL2_WIDTH; // 200px per tabel
  const ROW_HEIGHT = 36;         // tinggi per baris (14pt + padding vertikal)
  const MAX_BOARD_SIZE = 2048;
  const TABLE_LIMIT = 5;

  // Hitung maksimum baris per tabel berdasarkan batas tinggi board
  const maxRowsPerTable = Math.floor(
    (MAX_BOARD_SIZE - 2 * VERTICAL_MARGIN) / ROW_HEIGHT
  );

  // Potong data jika terlalu banyak (TABLE_LIMIT * maxRowsPerTable)
  const maxTotalRows = TABLE_LIMIT * maxRowsPerTable;
  let items = arr.slice();
  if (items.length > maxTotalRows) {
    items = items.slice(0, maxTotalRows);
    console.warn(`createColorList: data dipotong menjadi ${maxTotalRows} baris (batas ukuran board)`);
  }

  // Tentukan jumlah tabel yang diperlukan (maksimal TABLE_LIMIT)
  const numTables = Math.min(TABLE_LIMIT, Math.ceil(items.length / maxRowsPerTable) || 1);
  
  // Distribusikan item ke masing-masing tabel (merata)
  const tableItems = [];
  const itemsPerTable = Math.ceil(items.length / numTables);
  for (let i = 0, start = 0; i < numTables; i++) {
    const end = Math.min(start + itemsPerTable, items.length);
    tableItems.push(items.slice(start, end));
    start = end;
  }

  // Cari jumlah baris terbanyak di antara semua tabel (untuk tinggi board)
  const maxRowsInAnyTable = Math.max(...tableItems.map(t => t.length));
  const contentHeight = maxRowsInAnyTable * ROW_HEIGHT;
  const boardHeight = Math.min(contentHeight + 2 * VERTICAL_MARGIN, MAX_BOARD_SIZE);
  
  const contentWidth = numTables * TABLE_WIDTH + (numTables - 1) * TABLE_MARGIN;
  const boardWidth = Math.min(contentWidth + 2 * HORIZONTAL_MARGIN, MAX_BOARD_SIZE);

  // Mulai membangun SVG
  let svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${boardWidth}" height="${boardHeight}" viewBox="0 0 ${boardWidth} ${boardHeight}">`;
  svg += `<rect width="100%" height="100%" fill="#ffffff" />`; // latar putih

  let xOffset = HORIZONTAL_MARGIN;
  const yStart = VERTICAL_MARGIN;

  for (let t = 0; t < numTables; t++) {
    const currentRows = tableItems[t];
    const tableX = xOffset;

    // Gambar setiap baris dalam tabel ini
    for (let i = 0; i < currentRows.length; i++) {
      const { name, color, colorName } = currentRows[i];
      const rowY = yStart + i * ROW_HEIGHT;
      const col2X = tableX + COL1_WIDTH;

      // Kolom 2: background warna
      svg += `<rect x="${col2X}" y="${rowY}" width="${COL2_WIDTH}" height="${ROW_HEIGHT}" fill="${color}" />`;

      // Kolom 1: teks nama (kiri, padding 8px)
      svg += `<text x="${tableX + 8}" y="${rowY + ROW_HEIGHT / 2}" font-size="14pt" font-family="'Noto Sans JP', Arial, sans-serif" fill="#000000" dominant-baseline="middle">${escapeXml(name)}</text>`;

      // Kolom 2: teks colorName dengan kontras otomatis
      const textColor = getContrastColor(color);
      svg += `<text x="${col2X + COL2_WIDTH / 2}" y="${rowY + ROW_HEIGHT / 2}" font-size="14pt" font-family="'Noto Sans JP', Arial, sans-serif" fill="${textColor}" text-anchor="middle" dominant-baseline="middle">${escapeXml(colorName)}</text>`;
    }

    // Opsional: border tipis di sekeliling tabel
    const tableHeight = maxRowsInAnyTable * ROW_HEIGHT;
    svg += `<rect x="${tableX}" y="${yStart}" width="${TABLE_WIDTH}" height="${tableHeight}" fill="none" stroke="#cccccc" stroke-width="1" />`;

    xOffset += TABLE_WIDTH + TABLE_MARGIN;
  }

  svg += `</svg>`;

  // Render SVG ke PNG menggunakan Sharp
  return await sharp(Buffer.from(svg)).png().toBuffer();
}

